PREFIX bd: <http://www.bigdata.com/rdf#>
SELECT ?birthplace ?birthplaceLabel
WHERE {
  ?player wdt:P27 wd:Q20 ;
          wdt:P2013 wd:Q5032 ;
          wdt:P54 ?clubStatement .
  ?clubStatement ps:P54 wd:Q526195 ;
                 pq:P585 ?time .
  FILTER (bd:year(?time) = 2007) .
  ?player wdt:P19 ?birthplace .
  OPTIONAL { ?birthplace rdfs:label ?birthplaceLabel . FILTER (langMatches(?birthplaceLabel, "EN")) }
}

